    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //
        //    {
        //        id: '7495738622',
        //        type: 'sell',
        //        time: '1699255565.445418',
        //        amount: '252.6',
        //        price: '0.3422'
        //    }
        //
        // fetchMyTrades
        //
        //    {
        //        "deal_id": 7450617292,              // Deal id
        //        "deal_time": 1698506956.66224,      // Deal execution time
        //        "deal_order_id": 171955225751,      // Deal order id
        //        "opposite_order_id": 171955110512,  // Opposite order id
        //        "side": "sell",                     // Deal side
        //        "price": "0.05231",                 // Deal price
        //        "amount": "0.002",                  // Deal amount
        //        "deal": "0.00010462",               // Total (price * amount)
        //        "deal_fee": "0.000000188316",       // Deal fee
        //        "role": "taker",                    // Role. Taker or maker
        //        "isSelfTrade": false                // is self trade
        //    }
        //
        // fetchOrderTrades
        //
        //    {
        //        "id": 7429883128,             // Deal id
        //        "time": 1698237535.41196,     // Deal execution time
        //        "fee": "0.01755848704",       // Deal fee
        //        "price": "34293.92",          // Deal price
        //        "amount": "0.00032",          // Deal amount
        //        "dealOrderId": 171366551416,  // Deal order id
        //        "role": 1,                    // Deal role (1 - maker, 2 - taker)
        //        "deal": "10.9740544"          // Total (price * amount)
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeIntegerProduct2(trade, "time", "deal_time", 1000);
        Object takerOrMaker = this.safeString(trade, "role");
        if (Helpers.isTrue(Helpers.isEqual(takerOrMaker, "1")))
        {
            takerOrMaker = "maker";
        } else if (Helpers.isTrue(Helpers.isEqual(takerOrMaker, "2")))
        {
            takerOrMaker = "taker";
        }
        final Object finalTakerOrMaker = takerOrMaker;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", P2bCore.this.safeString2(trade, "id", "deal_id") );
            put( "timestamp", timestamp );
            put( "datetime", P2bCore.this.iso8601(timestamp) );
            put( "symbol", P2bCore.this.safeString(market, "symbol") );
            put( "order", P2bCore.this.safeString2(trade, "dealOrderId", "deal_order_id") );
            put( "type", null );
            put( "side", P2bCore.this.safeString2(trade, "type", "side") );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", P2bCore.this.safeString(trade, "price") );
            put( "amount", P2bCore.this.safeString(trade, "amount") );
            put( "cost", P2bCore.this.safeString(trade, "deal") );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", P2bCore.this.safeString(market, "quote") );
                put( "cost", P2bCore.this.safeString2(trade, "fee", "deal_fee") );
            }} );
        }}, market);
    }

